import{_ as e,o as s,c as d,a2 as r}from"./chunks/framework.BFZItJIV.js";const u=JSON.parse('{"title":"Benchmarks","description":"TalaDB performance benchmarks — document write throughput, indexed query latency, and on-device vector search timings for Node.js (native) and the browser (WASM + OPFS), measured with the open-source suites in scripts/.","frontmatter":{"title":"Benchmarks","description":"TalaDB performance benchmarks — document write throughput, indexed query latency, and on-device vector search timings for Node.js (native) and the browser (WASM + OPFS), measured with the open-source suites in scripts/."},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md"}'),a={name:"benchmarks.md"};function o(n,t,i,c,l,h){return s(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Real numbers, measured honestly. All results below come from the two benchmark suites that ship in the repository, so you can reproduce every row on your own hardware:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Node.js (native module)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @taladb/node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Browser (WASM + OPFS — drives your installed Chrome headlessly)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @taladb/web</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:web</span></span></code></pre></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>TalaDB</td><td>v0.8.3, release builds</td></tr><tr><td>Machine</td><td>2018 MacBook Pro — Intel i5-8259U @ 2.30 GHz, 8 GB RAM</td></tr><tr><td>Node.js runtime</td><td>Node v22 · <code>@taladb/node</code> (napi) · file-backed database</td></tr><tr><td>Browser runtime</td><td>Chrome 149 headless · <code>@taladb/web</code> (WASM) · OPFS-backed</td></tr><tr><td>Date</td><td>2026-07-09</td></tr></tbody></table><p>Latencies are the <strong>median</strong> of repeated timed iterations after warmup, with deterministic seeded data. Documents are realistic small records (~7 fields); vectors are 384-dimensional unit vectors — the output shape of <code>all-MiniLM-L6-v2</code>, the most common on-device embedding model. The Node suite uses the raw N-API binding; the browser suite drives the <code>@taladb/web</code> worker over its message protocol. In both cases that is the same path the <code>taladb</code> wrapper uses, so timings include everything an application pays.</p><p>This is deliberately modest hardware. On a recent Apple Silicon or desktop-class machine, expect meaningfully better numbers across the board.</p><h2 id="node-js-—-document-writes" tabindex="-1">Node.js — document writes <a class="header-anchor" href="#node-js-—-document-writes" aria-label="Permalink to &quot;Node.js — document writes&quot;">​</a></h2><p>File-backed, every operation durable on disk when the call returns.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>insert</code> (single doc)</td><td>one transaction per call</td><td><strong>~47 ops/s</strong></td></tr><tr><td><code>insertMany</code> (batch 100)</td><td>single transaction per batch</td><td><strong>~3.9k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 1,000)</td><td>single transaction per batch</td><td><strong>~19k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 5,000)</td><td>single transaction per batch</td><td><strong>~36k docs/s</strong></td></tr><tr><td><code>updateOne</code> (by <code>_id</code>)</td><td>point update, <code>$set</code> one field</td><td><strong>~47 ops/s</strong></td></tr><tr><td><code>deleteOne</code> (by <code>_id</code>)</td><td>point delete</td><td><strong>~46 ops/s</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Batch your writes</p><p>Every individual write is a full ACID transaction — the ~47 ops/s ceiling for single-document calls is the cost of a durable commit to disk (redb <code>fsync</code>), not of TalaDB&#39;s write path. The same machine sustains <strong>36k docs/s</strong> when writes share a transaction. If you are inserting more than a handful of documents, use <code>insertMany</code>.</p></div><h2 id="node-js-—-query-latency-at-100-000-documents" tabindex="-1">Node.js — query latency at 100,000 documents <a class="header-anchor" href="#node-js-—-query-latency-at-100-000-documents" aria-label="Permalink to &quot;Node.js — query latency at 100,000 documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>findOne</code> by <code>_id</code></td><td>primary-key point get</td><td><strong>25 µs</strong></td></tr><tr><td><code>find</code>, indexed equality</td><td>secondary index, ~10 matches</td><td><strong>169 µs</strong></td></tr><tr><td><code>find</code>, indexed range (<code>$gte</code>)</td><td>newest ~100 docs by <code>publishedAt</code></td><td><strong>1.4 ms</strong></td></tr><tr><td><code>find</code>, unindexed field</td><td>full scan of 100k docs</td><td><strong>437 ms</strong></td></tr><tr><td><code>count</code>, unindexed equality</td><td>scan, 12.5k matches</td><td><strong>464 ms</strong></td></tr></tbody></table><p>Point gets and indexed lookups stay in the microsecond range at 100k documents — the B-tree index layout gives <code>O(log n)</code> lookups regardless of collection size. Unindexed queries fall back to a full collection scan; if a field appears in your filters regularly, <code>createIndex</code> turns a 437 ms scan into a 169 µs lookup — a <strong>~2,600×</strong> difference.</p><div class="warning custom-block"><p class="custom-block-title">Two-sided ranges</p><p>The query planner is currently greedy rather than cost-based: a two-sided range (<code>$gte</code> + <code>$lt</code> on the same field) uses the index for the lower bound only and post-filters the rest, so it can scan far more index entries than the window contains (~463 ms for a ~100-doc window at 100k docs, versus 1.4 ms for the one-sided form). Bounded range plans are on the roadmap. Until then, prefer one-sided ranges on recent data, or an indexed equality alongside the range.</p></div><h2 id="node-js-—-vector-search-384-dim-cosine-top-10" tabindex="-1">Node.js — vector search (384-dim, cosine, top-10) <a class="header-anchor" href="#node-js-—-vector-search-384-dim-cosine-top-10" aria-label="Permalink to &quot;Node.js — vector search (384-dim, cosine, top-10)&quot;">​</a></h2><p>The default (flat) index is exact k-nearest-neighbour over all vectors — no approximation, no recall trade-off.</p><table tabindex="0"><thead><tr><th>Collection size</th><th><code>findNearest</code> (median)</th></tr></thead><tbody><tr><td>1,000 vectors</td><td><strong>4.0 ms</strong></td></tr><tr><td>10,000 vectors</td><td><strong>40 ms</strong></td></tr><tr><td>50,000 vectors</td><td><strong>188 ms</strong></td></tr><tr><td>100,000 vectors</td><td><strong>369 ms</strong></td></tr></tbody></table><p>Hybrid search — metadata pre-filter, then rank — costs roughly the same as pure vector search when the filter field is indexed:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>findNearest</code> + filter, 100k vectors</td><td>indexed pre-filter matching 10% of docs, then rank</td><td><strong>448 ms</strong></td></tr><tr><td>Vector ingest, 100k vectors</td><td><code>insertMany</code> with a live vector index</td><td><strong>~4.6k docs/s</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Index your filter fields</p><p>The hybrid pre-filter is an ordinary document query, so it benefits from secondary indexes exactly like <code>find</code> does. In this suite, indexing the filter field brought filtered search from ~3 s down to 448 ms at 100k vectors.</p></div><p>For context: a typical on-device semantic search corpus (notes app, offline docs, chat history) is 1k–10k chunks, where exact search answers in <strong>~40 ms or less</strong> — faster than a network round-trip to any cloud vector database, with zero data leaving the device.</p><h3 id="optional-hnsw-index-node-js-since-0-8-3" tabindex="-1">Optional HNSW index (Node.js, since 0.8.3) <a class="header-anchor" href="#optional-hnsw-index-node-js-since-0-8-3" aria-label="Permalink to &quot;Optional HNSW index (Node.js, since 0.8.3)&quot;">​</a></h3><p>For larger corpora, <code>@taladb/node</code> ships with an approximate HNSW index (<code>createVectorIndex(field, { dimensions, indexType: &#39;hnsw&#39; })</code>):</p><table tabindex="0"><thead><tr><th>Metric</th><th>50,000 × 384-dim vectors</th></tr></thead><tbody><tr><td><code>findNearest</code> (HNSW)</td><td><strong>14.6 ms</strong> (vs 188 ms flat — ~13× faster)</td></tr><tr><td>Graph build (one-off)</td><td><strong>~30 min</strong> on this hardware (47 s at 10k)</td></tr><tr><td>recall@10, uniform random vectors</td><td>38% — the adversarial worst case</td></tr><tr><td>recall@10, clustered vectors (embedding-like structure)</td><td><strong>100%</strong></td></tr></tbody></table><p>Read the recall rows carefully: uniform random vectors have no neighbourhood structure and are the known worst case for graph-based ANN. Real model embeddings are strongly clustered, where HNSW recall is excellent — but measure on <em>your</em> data before relying on it. Two operational caveats: the graph is built at <code>createVectorIndex</code> / <code>upgradeVectorIndex</code> time and is <strong>not</strong> updated by later writes (rebuild during idle periods after bulk ingests), and graph construction is CPU-intensive — plan the one-off build cost. The flat index stays the right default for most on-device corpora; <code>@taladb/web</code> and React Native are currently flat-only.</p><h2 id="browser-—-wasm-opfs-chrome-headless" tabindex="-1">Browser — WASM + OPFS (Chrome headless) <a class="header-anchor" href="#browser-—-wasm-opfs-chrome-headless" aria-label="Permalink to &quot;Browser — WASM + OPFS (Chrome headless)&quot;">​</a></h2><p>The same operations, measured against the <code>@taladb/web</code> worker in a real Chrome instance with OPFS active. Every timing includes the page ↔ worker <code>postMessage</code> round-trip and JSON serialisation.</p><h3 id="document-writes" tabindex="-1">Document writes <a class="header-anchor" href="#document-writes" aria-label="Permalink to &quot;Document writes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>insert</code> (single doc)</td><td>one transaction per call</td><td><strong>~1.0k ops/s</strong></td></tr><tr><td><code>insertMany</code> (batch 100)</td><td>single transaction per batch</td><td><strong>~26k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 1,000)</td><td>single transaction per batch</td><td><strong>~43k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 5,000)</td><td>single transaction per batch</td><td><strong>~57k docs/s</strong></td></tr><tr><td><code>updateOne</code> (by <code>_id</code>)</td><td>point update, <code>$set</code> one field</td><td><strong>~625 ops/s</strong></td></tr><tr><td><code>deleteOne</code> (by <code>_id</code>)</td><td>point delete</td><td><strong>~714 ops/s</strong></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Different durability model</p><p>Browser writes are much faster than Node&#39;s single-write numbers because the durability guarantee is different. In the browser the engine is memory-resident and the worker persists a snapshot to OPFS on a <strong>500 ms debounce</strong> (plus a final flush on <code>close()</code> and before releasing the multi-tab lock). A hard crash of the browser process can lose the last ≤ 500 ms of writes. On Node.js every committed transaction is <code>fsync</code>ed before the call returns. This is the right trade-off for local-first browser apps — but don&#39;t read these two write columns as the same guarantee.</p></div><h3 id="query-latency-at-100-000-documents" tabindex="-1">Query latency at 100,000 documents <a class="header-anchor" href="#query-latency-at-100-000-documents" aria-label="Permalink to &quot;Query latency at 100,000 documents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Browser</th><th>Node.js</th></tr></thead><tbody><tr><td><code>findOne</code> by <code>_id</code></td><td>primary-key point get</td><td><strong>100 µs</strong></td><td>25 µs</td></tr><tr><td><code>find</code>, indexed equality</td><td>secondary index, ~10 matches</td><td><strong>300 µs</strong></td><td>169 µs</td></tr><tr><td><code>find</code>, indexed range (<code>$gte</code>)</td><td>newest ~100 docs</td><td><strong>800 µs</strong></td><td>1.4 ms</td></tr><tr><td><code>find</code>, unindexed field</td><td>full scan of 100k docs</td><td><strong>157 ms</strong></td><td>437 ms</td></tr><tr><td><code>count</code>, unindexed equality</td><td>scan, 12.5k matches</td><td><strong>166 ms</strong></td><td>464 ms</td></tr></tbody></table><p>Sub-millisecond operations pay the worker <code>postMessage</code> round-trip (~50–100 µs), so browser point reads land around 100–300 µs — still far below anything network-bound. Scans are actually <em>faster</em> in the browser because the memory-resident engine reads no disk pages.</p><h3 id="vector-search-384-dim-cosine-top-10-flat" tabindex="-1">Vector search (384-dim, cosine, top-10, flat) <a class="header-anchor" href="#vector-search-384-dim-cosine-top-10-flat" aria-label="Permalink to &quot;Vector search (384-dim, cosine, top-10, flat)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Collection size</th><th><code>findNearest</code> (median)</th><th>Node.js</th></tr></thead><tbody><tr><td>1,000 vectors</td><td><strong>5.3 ms</strong></td><td>4.0 ms</td></tr><tr><td>10,000 vectors</td><td><strong>35 ms</strong></td><td>40 ms</td></tr><tr><td>50,000 vectors</td><td><strong>171 ms</strong></td><td>188 ms</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>findNearest</code> + filter, 50k vectors</td><td>indexed pre-filter matching 10%, then rank</td><td><strong>159 ms</strong></td></tr><tr><td>Vector ingest, 50k vectors</td><td><code>insertMany</code> with a live vector index</td><td><strong>~2.3k docs/s</strong></td></tr></tbody></table><p>WASM vector search runs at parity with the native module — the scan is pure Rust arithmetic in both builds, and semantic search over a typical 1k–10k chunk corpus stays <strong>under 40 ms</strong> in the browser too.</p><h2 id="reading-these-numbers" tabindex="-1">Reading these numbers <a class="header-anchor" href="#reading-these-numbers" aria-label="Permalink to &quot;Reading these numbers&quot;">​</a></h2><ul><li><strong>Scaling</strong> — exact vector search is linear in collection size; document point lookups are logarithmic. Both behave predictably as your data grows.</li><li><strong>Latency floor, not ceiling</strong> — the test machine is a 2018 dual-fan ultrabook. Treat these as conservative.</li><li><strong>Durability differs by platform</strong> — Node.js commits are <code>fsync</code>-durable per transaction; the browser engine is memory-resident with a 500 ms debounced OPFS snapshot flush (see the note above). Same API, different persistence guarantee.</li><li><strong>React Native</strong> — the same Rust core runs on React Native via JSI with a file-backed database like Node.js; a runtime-specific suite is planned.</li><li><strong>Methodology</strong> — deterministic seeded data, warmup before measurement, medians reported, one process at a time on an otherwise idle machine. Read <a href="https://github.com/thinkgrid-labs/taladb/blob/main/scripts/bench.mjs" target="_blank" rel="noreferrer"><code>scripts/bench.mjs</code></a> (Node) and <a href="https://github.com/thinkgrid-labs/taladb/blob/main/scripts/bench-web.mjs" target="_blank" rel="noreferrer"><code>scripts/bench-web.mjs</code></a> + <a href="https://github.com/thinkgrid-labs/taladb/blob/main/scripts/bench-web/bench.browser.js" target="_blank" rel="noreferrer"><code>scripts/bench-web/bench.browser.js</code></a> (browser) for the exact workloads.</li></ul>`,40)])])}const b=e(a,[["render",o]]);export{u as __pageData,b as default};
